e_portal->addField('sort',$sort);		$this->rpc_service_portal->addField('limit',$limit);		$this->rpc_service_portal->addField('offset',$offset);				$this->rpc_service_portal->setWhere($search,$filterRules,$field);				$result = $this->rpc_service_portal->resultJSON();			$data_result = json_decode($result['data'],true);				if(isset($data_result['detail']['result_count'])){			$records = $data_result['detail']['result_count'];			$total = ceil($data_result['detail']['result_count'] / $limit);		} else {			$records = 0;			$total = 0;		}				$responce = new stdclass();		$responce->page = $page;		$responce->records = $records;		$responce->total = $total;		$i=0; 		if($data_result){			if(isset($data_result['xrow'])){				foreach($data_result['xrow'] as $key=>$value){					foreach ($value as $k => $v) {						$responce->rows[$i][$k] = $v;					} 										$responce->rows[$i]['selected_row'] = $responce->rows[$i]['r7'];										$i++;				}			}		}					$return = json_encode($responce);					echo $return;	}		function loaddata_detail_total(){		$this->authentication->plainlayout();				$field = array();		$field[] = array('field' => 'item', 'title' => 'item');		$field[] = array('field' => 'quantity_requirement', 'title' => 'unit');		$field[] = array('field' => 'uom_code', 'title' => 'mat_quantity');		$field[] = array('field' => 'fg_item', 'title' => 'mat_quantity');		$field[] = array('field' => 'quantity_warehouse_return', 'title' => 'mat_quantity');			$new_warehouse_return = isset($_POST['new_warehouse_return']) ? $_POST['new_warehouse_return'] : 0;		$warehouse_return_id = isset($_POST['warehouse_return_id']) ? is_numeric($_POST['warehouse_return_id']) ? $_POST['warehouse_return_id'] : -1: -1;		$return = array();		$return['valid'] = false;		$return['message'] = "Internal Server Error";		$loaddata_table = array();						$view = 'dbo.view_warehouse_return_detail';		$where = array();		$where['warehouse_return_id'] = $warehouse_return